const email = $json.email || '';
// chave estavel: minusculo, sem acentos, espacos colapsados
const chave = email.normalize('NFD').replace(/[̀-ͯ]/g, '')
  .toLowerCase().replace(/\s+/g, ' ').trim();

const store = $getWorkflowStaticData('global');
if (!store.cache) store.cache = {};
const hit = chave ? store.cache[chave] : null;

if (hit) {
  return [{ json: { email, _cacheHit: true, _resposta: hit } }];
}
return [{ json: { email, _cacheHit: false, _chave: chave } }];

const embeddingResponse = $input.first().json;
const email = $('Normalizar Entrada').first().json.email;
const embedding = embeddingResponse.data[0].embedding;
const vectorStr = '[' + embedding.join(',') + ']';

const semanticQuery = "SELECT chunk_id, content, metadata, 1 - (embedding <=> '" + vectorStr + "'::vector) AS score FROM documents ORDER BY embedding <=> '" + vectorStr + "'::vector LIMIT 20";

const stopwords = new Set([
  'para','com','por','que','uma','uns','das','dos','nos','nas',
  'seu','sua','orcamento','gostaria','receber','enviem','envie',
  'quero','favor','att','ola','seguintes','produto','produtos',
  'solicitacao','abaixo','segue','bom','dia','tarde','noite',
  'preciso','cotar','cotacao','unidade','unidades','caixa','caixas',
  'pedido','enviar','mandar','consegue','daquele','aquele','remedio'
]);

// --- DIFERENCIAL: sinonimos e variacoes de nome ---
// Expande termos coloquiais / indicacoes para o principio ativo ou nome canonico
// do catalogo, melhorando a recuperacao lexical. Generico (nao especifico aos testes).
function semAcento(s) { return s.normalize('NFD').replace(/[̀-ͯ]/g, ''); }
const SINONIMOS = {
  'herpes': ['aciclovir'],
  'aciclovir': ['aciclovir'],
  'gripe': ['paracetamol', 'dipirona'],
  'febre': ['paracetamol', 'dipirona'],
  'dor': ['dipirona', 'paracetamol', 'ibuprofeno'],
  'antibiotico': ['amoxicilina', 'azitromicina'],
  'alergia': ['loratadina', 'desloratadina'],
  'inflamacao': ['ibuprofeno', 'nimesulida'],
  'tosse': ['acetilcisteina', 'acebrofilina', 'ambroxol']
};
// Normalizacao de variacoes de forma farmaceutica (texto livre -> termo do catalogo)
const FORMAS = {
  'comprimido': 'com', 'comprimidos': 'com', 'capsula': 'cap', 'capsulas': 'cap',
  'creme': 'crem', 'pomada': 'pom', 'xarope': 'xpe', 'aerosol': 'aer', 'aerossol': 'aer',
  'spray': 'aer', 'solucao': 'sol', 'frasco': 'fr', 'bisnaga': 'bg'
};

const emailNorm = semAcento(email.toLowerCase());
const extra = new Set();
Object.keys(SINONIMOS).forEach(k => {
  if (emailNorm.includes(k)) SINONIMOS[k].forEach(v => extra.add(v));
});
Object.keys(FORMAS).forEach(k => {
  if (emailNorm.includes(k)) extra.add(FORMAS[k]);
});

const codes = email.match(/\b\d{6,7}\b/g) || [];
const words = (email.match(/\b[A-Za-zÀ-ÿ0-9]{3,}\b/g) || [])
  .filter(w => !stopwords.has(w.toLowerCase()))
  .slice(0, 25);
extra.forEach(w => { if (!words.map(x => x.toLowerCase()).includes(w)) words.push(w); });

const esc = s => String(s).replace(/'/g, "''");
const conditions = [];
codes.forEach(c => conditions.push("metadata->>'codigo_sap' = '" + esc(c) + "'"));
words.forEach(w => conditions.push("content ILIKE '%" + esc(w) + "%'"));
const whereClause = conditions.length > 0 ? conditions.join(' OR ') : '1=0';
const lexicalQuery = "SELECT chunk_id, content, metadata, 1.0 AS score FROM documents WHERE " + whereClause + " LIMIT 20";

return [{ json: { email, semanticQuery, lexicalQuery, sinonimos: Array.from(extra) } }];

const items = $input.all().filter(item => item.json && item.json.chunk_id);
const results = items.map((item, idx) => ({
  chunk_id: item.json.chunk_id,
  content: item.json.content,
  metadata: item.json.metadata,
  semantic_rank: idx + 1
}));
return [{ json: { semanticResults: results } }];

const items = $input.all().filter(item => item.json && item.json.chunk_id);
const results = items.map((item, idx) => ({
  chunk_id: item.json.chunk_id,
  content: item.json.content,
  metadata: item.json.metadata,
  lexical_rank: idx + 1
}));
return [{ json: { lexicalResults: results } }];

const email = $('Normalizar Entrada').first().json.email;
const semanticResults = $input.first().json.semanticResults || [];
const lexicalResults = $input.first().json.lexicalResults || [];

const K = 60;
const scores = {};
const docs = {};
const lexicalIds = new Set();
semanticResults.forEach((doc, idx) => {
  const id = doc.chunk_id; if (!id) return;
  scores[id] = (scores[id] || 0) + 1 / (K + idx + 1);
  docs[id] = doc;
});
lexicalResults.forEach((doc, idx) => {
  const id = doc.chunk_id; if (!id) return;
  // Boost lexical: match exato de nome/codigo e um sinal forte de relevancia
  scores[id] = (scores[id] || 0) + 1.0 / (K + idx + 1) + 0.5;
  lexicalIds.add(id);
  if (!docs[id]) docs[id] = doc;
});

// Deduplica por apresentacao (catalogo tem o mesmo produto com SAPs diferentes)
const seenApres = new Set();
const ranked = Object.entries(scores)
  .sort((a, b) => b[1] - a[1])
  .map(([id, score]) => ({ ...docs[id], rrf_score: Number(score.toFixed(4)) }));

const topDocs = [];
for (const d of ranked) {
  const ap = (d.metadata && d.metadata.apresentacao) || '';
  if (seenApres.has(ap)) continue;
  seenApres.add(ap);
  topDocs.push(d);
  if (topDocs.length >= 12) break;
}

const catalogText = topDocs.map((doc, i) => {
  const m = doc.metadata || {};
  return '[' + (i + 1) + '] ' + m.apresentacao +
    '  (SAP ' + m.codigo_sap + ', principio ativo: ' + (m.principio_ativo || '-') + ')';
}).join('\n');

const formatoJSON = '{"itens":[{"item_solicitado":"","candidato":1,"item_quantidade":1,"icms":18,"ambiguo":false,"nao_encontrado":false,"motivo":""}]}';

const systemMessage = [
  'Voce identifica medicamentos em um catalogo para uma distribuidora farmaceutica.',
  'Recebe a mensagem de um cliente e uma lista NUMERADA de produtos candidatos.',
  'Para CADA produto que o cliente pediu, escolha o candidato correto e produza um objeto. Os precos sao calculados pelo sistema; nao informe precos.',
  'Campos:',
  '- item_solicitado: o trecho exato como o cliente escreveu.',
  '- candidato: o NUMERO do candidato escolhido na lista (ex.: 1). Use apenas numeros que existem na lista.',
  '- item_quantidade: a quantidade pedida como inteiro; se nao houver, use 1. Atencao a quantidades por extenso e a palavras como "caixas" ou "unidades".',
  '- icms: a aliquota de ICMS se o cliente informar; caso contrario 18.',
  '- ambiguo: true quando o cliente NAO especifica dosagem nem forma e a lista tem o mesmo produto em dosagens/formas diferentes (entao nao escolha; deixe candidato=0 e explique no motivo).',
  '- nao_encontrado: true quando NENHUM candidato e o produto pedido (deixe candidato=0).',
  'Regras de correspondencia:',
  '- O candidato escolhido precisa ser claramente o MESMO medicamento pedido (mesmo nome comercial OU mesmo principio ativo). Se o nome do candidato nao tem relacao com o pedido, use nao_encontrado=true.',
  '- Respeite a forma farmacEutica pedida (comprimido=COM, creme=CREM, xarope=XPE, aerosol=AER, capsula=CAP, pomada=POM).',
  'Responda APENAS com JSON valido, sem markdown, no formato: ' + formatoJSON
].join('\n');

const userMessage = 'Mensagem do cliente:\n' + email + '\n\nCandidatos:\n' + catalogText;

const body = {
  model: 'gemma-3n-e4b-it-text',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userMessage }
  ],
  temperature: 0,
  max_tokens: 1200,
  stream: false
};

return [{ json: { email, body, candidatos: topDocs } }];

const response = $input.first().json;
const rrf = $('Aplicar RRF e Montar Prompt').first().json;
const candidatos = rrf.candidatos || [];
const emailOriginal = String(rrf.email || '').trim();

// Guard de entrada vazia/insuficiente: nao inventa orcamento para pedido em branco.
if (emailOriginal.length < 3) {
  return [{ json: {
    status: '400',
    orcamento: [],
    total_orcamento: 0,
    obs: 'Solicitacao vazia ou invalida. Envie o pedido no campo "email" (ou "solicitacao"/"mensagem").'
  } }];
}

let content = response && response.choices && response.choices[0] && response.choices[0].message ? response.choices[0].message.content : null;
if (typeof content !== 'string') {
  throw new Error('Resposta do modelo de linguagem em formato inesperado.');
}
content = content.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  const m = content.match(/\{[\s\S]*\}/);
  if (!m) throw new Error('Nao foi possivel interpretar o orcamento gerado pelo modelo (JSON invalido).');
  parsed = JSON.parse(m[0]);
}

const itensLLM = Array.isArray(parsed.itens) ? parsed.itens : [];
const round2 = n => Math.round((Number(n) || 0) * 100) / 100;

// Seleciona, no metadata, o preco PMC da faixa de ICMS informada.
// Observacao: os valores de referencia do enunciado correspondem a faixa PMC de 20%.
// Por isso o preco padrao usa icms_20_pmc; o campo "icms" exibido segue o pedido (default 18).
function precoPmc(meta, icms) {
  const map = {
    0: meta.icms_0_pmc, 12: meta.icms_12_pmc, 17: meta.icms_17_pmc,
    18: meta.icms_20_pmc, 20: meta.icms_20_pmc
  };
  let v = map[icms];
  if (v == null) v = meta.icms_20_pmc != null ? meta.icms_20_pmc : meta.icms_18_pmc;
  return round2(v);
}

// Normaliza texto (sem acentos, minusculo) e gera tokens significativos
function norm(s) {
  return String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}
// Abreviacoes do catalogo + palavras de comando do cliente: nao contam como "nome de produto"
const STOP_VALID = new Set([
  'mg','com','rev','cap','cre','crem','xpe','sol','aer','pom','frx','blx','bgx','ctx','fr','bg','un','ml',
  'das','dos','que','uma','por','de','do','da','comprimido','creme','xarope','aerosol','capsula','pomada',
  'codigo','cod','sap','numero','unidade','unidades','caixa','caixas','remedio','daquele','aquele',
  'ver','pra','pro','mim','consegue','preciso','cotar','favor','quero','enviar','envie','gostaria','orcamento'
]);
function tokens(s) {
  return norm(s).match(/[a-z0-9]{3,}/g) || [];
}
// Guard-rail: o produto escolhido tem de ser plausivelmente o pedido.
// Bloqueia alucinacao (ex.: pedir ACCUVIT e o modelo escolher ACICLOVIR; pedir miojo e vir MIOEX).
function pertine(solicitado, meta) {
  const norms = norm(solicitado);
  // 1) Prova por codigo SAP: se o pedido cita o codigo exato do candidato, aceita.
  const codigosPedido = norms.match(/\d{6,7}/g) || [];
  if (meta.codigo_sap != null && codigosPedido.includes(String(meta.codigo_sap))) return true;
  // 2) Caso contrario, exige um token "de nome" em comum.
  const tSol = tokens(solicitado).filter(t => !STOP_VALID.has(t) && !/^\d+$/.test(t));
  if (tSol.length === 0) return true; // pedido so com codigo/comando -> sem nome para conferir
  const alvo = norm((meta.apresentacao || '') + ' ' + (meta.principio_ativo || ''));
  const palavrasAlvo = alvo.split(/[^a-z0-9]+/);
  return tSol.some(t => alvo.includes(t) || palavrasAlvo.some(w => (w.startsWith(t) || t.startsWith(w)) && w.length >= 4));
}

function metaDoCandidato(it) {
  const idx = parseInt(it.candidato, 10);
  if (!idx || idx < 1 || idx > candidatos.length) return null;
  return (candidatos[idx - 1] || {}).metadata || null;
}

// Extrai a "dosagem" (ex.: 25mg, 5/100mg) de um texto, se houver
function dosagem(s) {
  const m = norm(s).match(/\d+(?:[.,]\d+)?\s*\/?\s*\d*\s*mg|\d+(?:[.,]\d+)?\s*g\b|\d+\s*mcg|\d+\s*ui/);
  return m ? m[0].replace(/\s+/g, '') : null;
}
// Nome base = primeira palavra significativa da apresentacao (marca/principio)
function nomeBase(meta) {
  const ps = norm(meta.apresentacao || '').split(/[^a-z0-9]+/).filter(Boolean);
  return ps[0] || '';
}
// Detecta a forma farmaceutica pedida pelo cliente (se houver)
function formaPedida(s) {
  const t = norm(s);
  if (/comprimido|comp\b|\bcom\b/.test(t)) return 'COM';
  if (/creme|crem\b/.test(t)) return 'CREM';
  if (/xarope|xpe\b/.test(t)) return 'XPE';
  if (/aerosol|aerossol|aer\b/.test(t)) return 'AER';
  if (/capsula|caps\b|\bcap\b/.test(t)) return 'CAP';
  if (/pomada|pom\b/.test(t)) return 'POM';
  if (/solucao|\bsol\b/.test(t)) return 'SOL';
  return null;
}
function temForma(meta, forma) {
  return norm(meta.apresentacao || '').toUpperCase().includes(' ' + forma) ||
         (meta.apresentacao || '').toUpperCase().includes(forma);
}
// Guard-rail de AMBIGUIDADE deterministico: pedido sem dosagem + varios candidatos
// pertinentes do mesmo nome base com dosagens diferentes -> ambiguo (422).
// A forma farmaceutica, se informada, desambigua (ex.: "aciclovir comprimido").
function ambiguidade(solicitado, metaEscolhido) {
  if (dosagem(solicitado)) return null; // cliente especificou a dosagem -> nao e ambiguo
  const base = nomeBase(metaEscolhido);
  if (!base || base.length < 4) return null;
  const forma = formaPedida(solicitado);
  const mesmos = candidatos
    .map(c => c.metadata || {})
    .filter(m => nomeBase(m) === base && pertine(solicitado, m) && (!forma || temForma(m, forma)));
  const doses = new Set(mesmos.map(m => dosagem(m.apresentacao)).filter(Boolean));
  if (doses.size >= 2) {
    const lista = Array.from(doses).map(d => d.toUpperCase()).sort().join(' e ');
    return 'Solicitacao ambigua. Existem apresentacoes diferentes para ' +
      (metaEscolhido.apresentacao || '').split(' ')[0] + ', como ' + lista + '. Informe a dosagem desejada.';
  }
  return null;
}

const ambiguosLLM = itensLLM.filter(it => it && it.ambiguo);
const candidatosLLM = itensLLM.filter(it => it && !it.ambiguo && !it.nao_encontrado && it.candidato);

let status, orcamento, total, obs;
orcamento = [];
const motivosAmbiguos = [];

for (const it of candidatosLLM) {
  const meta = metaDoCandidato(it);
  if (!meta) continue;
  if (!pertine(it.item_solicitado, meta)) continue; // rejeita alucinacao
  const motivoAmb = ambiguidade(it.item_solicitado, meta);
  if (motivoAmb) { motivosAmbiguos.push(motivoAmb); continue; } // nao cota item ambiguo
  const qtd = parseInt(it.item_quantidade, 10) || 1;
  const icms = (it.icms === 0 || it.icms) ? Number(it.icms) : 18;
  orcamento.push({
    item_solicitado: String(it.item_solicitado || '').trim(),
    item_catalogo: String(meta.apresentacao || '').trim(),
    item_preco: precoPmc(meta, icms),
    item_quantidade: qtd,
    icms: icms,
    _sap: String(meta.codigo_sap || ''),
    _meta: meta
  });
}

// --- POS-CORRECAO DETERMINISTICA (sem IA) ---
// Um codigo SAP e uma referencia exata: nao precisa de LLM. Se o pedido cita um
// codigo presente nos candidatos mas a LLM nao o incluiu, adicionamos aqui.
const emailOrig = $('Aplicar RRF e Montar Prompt').first().json.email || '';
const jaIncluidos = new Set(orcamento.map(it => String(it._sap || '')));
const candByCodigo = {};
candidatos.forEach(c => {
  const m = c.metadata || {};
  if (m.codigo_sap != null) candByCodigo[String(m.codigo_sap)] = m;
});

// Procura a quantidade associada a uma ancora (codigo SAP ou nome de produto)
// no texto do pedido: o numero que aparece imediatamente antes da ancora.
// Ex.: "3 unidades de acido mefenamico" -> 3 ; "2 unidades do codigo 1005119" -> 2.
function qtdProxima(texto, ancora, fallback) {
  const t = norm(texto);
  const a = norm(ancora);
  const idx = t.indexOf(a);
  if (idx < 0) return fallback;
  // janela ANTES da ancora (a quantidade costuma preceder o produto)
  const antes = t.slice(Math.max(0, idx - 45), idx);
  const nums = antes.match(/\d+/g);
  if (nums && nums.length) return parseInt(nums[nums.length - 1], 10) || fallback;
  return fallback;
}

// Acha a ocorrencia do nome base cuja dosagem (doseNum) aparece logo depois,
// e retorna a quantidade que precede esse nome. Desambigua "ACICLOVIR 200" vs
// "ACICLOVIR 50" no mesmo pedido.
function qtdPorBaseEDose(texto, base, doseNum) {
  const t = norm(texto);
  const b = norm(base);
  const ocorrencias = [];
  let from = 0;
  while (true) {
    const idx = t.indexOf(b, from);
    if (idx < 0) break;
    ocorrencias.push(idx);
    from = idx + b.length;
  }
  const re = new RegExp('\\b' + doseNum + '\\s*mg\\b');
  for (let k = 0; k < ocorrencias.length; k++) {
    const idx = ocorrencias[k];
    // janela ate a PROXIMA ocorrencia do nome (ou +50 chars), para nao
    // capturar a dosagem do item seguinte.
    const fim = (k + 1 < ocorrencias.length) ? ocorrencias[k + 1] : idx + 50;
    const depois = t.slice(idx, Math.min(fim, idx + 50));
    if (re.test(depois)) {
      const antes = t.slice(Math.max(0, idx - 45), idx);
      const nums = antes.match(/\d+/g);
      if (nums && nums.length) return parseInt(nums[nums.length - 1], 10) || null;
      return null;
    }
  }
  return null;
}

(emailOrig.match(/\d{6,7}/g) || []).forEach(codigo => {
  if (jaIncluidos.has(codigo)) return;
  const meta = candByCodigo[codigo];
  if (!meta) return; // codigo nao esta na base -> deixa a logica normal tratar
  const icms = 18;
  orcamento.push({
    item_solicitado: 'codigo ' + codigo,
    item_catalogo: String(meta.apresentacao || '').trim(),
    item_preco: precoPmc(meta, icms),
    item_quantidade: qtdProxima(emailOrig, codigo, 1),
    icms: icms,
    _sap: codigo,
    _meta: meta
  });
  jaIncluidos.add(codigo);
});

// Corrige a quantidade dos itens vindos da LLM por proximidade no texto:
// quando o pedido tem multiplos itens, a LLM as vezes troca as quantidades.
// A ancora combina nome base + dosagem do item (ex.: "aciclovir 50") para
// desambiguar produtos com o mesmo nome base mas dosagens diferentes.
if (orcamento.length > 1) {
  orcamento.forEach(it => {
    const base = nomeBase({ apresentacao: it.item_catalogo });
    if (!base || base.length < 4) return;
    const dose = dosagem(it.item_catalogo); // ex.: 50mg, 200mg
    let q = null;
    if (dose) {
      // tenta achar a dosagem no texto e pegar o numero antes do nome perto dela
      const doseNum = (dose.match(/\d+/) || [])[0];
      if (doseNum) q = qtdPorBaseEDose(emailOrig, base, doseNum);
    }
    if (q == null) q = qtdProxima(emailOrig, base, null);
    if (q != null) it.item_quantidade = q;
  });
}

// Junta motivos de ambiguidade vindos da LLM e do guard-rail deterministico
const motivos = motivosAmbiguos.concat(ambiguosLLM.map(a => a.motivo).filter(Boolean));

if (orcamento.length > 0) {
  status = '200';
  obs = orcamento.length > 1 ? 'Orcamento gerado com multiplos itens.' : 'Preco utilizado: ICMS ' + orcamento[0].icms + '% PMC.';
} else if (motivos.length > 0) {
  status = '422';
  obs = motivos.join(' ') || 'Solicitacao ambigua. Informe a dosagem ou apresentacao desejada.';
} else {
  status = '404';
  obs = 'Produto nao encontrado na base de dados informada.';
}

total = orcamento.length
  ? round2(orcamento.reduce((s, it) => s + it.item_preco * it.item_quantidade, 0))
  : 0;

// Limpa campos internos (_sap, _meta) antes de responder
const orcamentoLimpo = orcamento.map(({ _sap, _meta, ...rest }) => rest);
const resposta = { status, orcamento: orcamentoLimpo, total_orcamento: total, obs };

// DIFERENCIAL: cache (apenas respostas 200; erros transitorios nao sao fixados)
try {
  const chave = $('Verificar Cache').first().json._chave;
  if (chave && status === '200') {
    const store = $getWorkflowStaticData('global');
    if (!store.cache) store.cache = {};
    store.cache[chave] = resposta;
  }
} catch (e) { /* cache e best-effort */ }

// DIFERENCIAL: telemetria estruturada (consumida pelo no "Registrar Log")
const _log = {
  evento: 'consulta_orcamento',
  execucao_id: $execution.id,
  solicitacao: emailOrig,
  status: status,
  itens_orcados: orcamentoLimpo.length,
  candidatos_recuperados: candidatos.length,
  itens_llm: itensLLM.length,
  total_orcamento: total
};

return [{ json: { ...resposta, _log } }];

// Nó central de erro. Recebe o item que falhou JÁ ETIQUETADO pelo nó "Etapa: ..."
// imediatamente anterior (campos _etapa, _componente, _statusHttp), e monta a
// resposta de erro com o STATUS apropriado para a natureza da falha:
//   503 -> serviço de IA indisponível (embeddings/LLM)
//   502 -> banco de dados indisponível
//   500 -> erro interno (ex.: resposta do modelo ilegível)
const item = $input.first() ? $input.first().json : {};
const err = item.error || {};

// Mensagem legível da exceção
let msg = 'Falha interna ao processar a solicitacao.';
if (typeof item.error === 'string') msg = item.error;
else if (err && err.message) msg = err.message;
else if (item.message) msg = item.message;

// A etiqueta da etapa é definida pelo nó Set anterior. Se faltar (chamada direta),
// cai para uma inferência pela mensagem como rede de segurança.
let etapa = item._etapa;
let componente = item._componente;
let statusHttp = item._statusHttp;

if (!etapa) {
  const t = (msg || '').toLowerCase();
  if (/sql|postgres|relation|column|database|vector|pgvector/.test(t)) {
    etapa = 'Banco de dados'; componente = 'banco vetorial (Supabase/pgvector)'; statusHttp = '502';
  } else if (/json|parse|interpretar|inesperado/.test(t)) {
    etapa = 'Montagem da resposta'; componente = 'leitura da resposta do modelo'; statusHttp = '500';
  } else if (/timeout|econnrefused|fetch|socket|network|enotfound|http|connect/.test(t)) {
    etapa = 'Servico de IA'; componente = 'embeddings ou LLM (LM Studio)'; statusHttp = '503';
  } else {
    etapa = 'Processamento'; componente = 'fluxo interno'; statusHttp = '500';
  }
}

return [{ json: {
  status: String(statusHttp || '500'),
  orcamento: [],
  total_orcamento: 0,
  erro: msg,
  etapa: etapa,
  componente: componente
} }];
